import React from 'react';

export default function ModalHapus({ produk, onKonfirmasi, onBatal }) {
  if (!produk) return null;

  const nama = produk.title.length > 50
    ? produk.title.slice(0, 50) + '…'
    : produk.title;

  return (
    <div className="overlay" onClick={onBatal}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <h3>Hapus Produk?</h3>
        <p>
          Kamu yakin ingin menghapus <strong>"{nama}"</strong>?
          Tindakan ini tidak bisa dibatalkan.
        </p>
        <div className="aksi-modal">
          <button className="tombol-konfirmasi-batal" onClick={onBatal}>Batal</button>
          <button className="tombol-konfirmasi-hapus" onClick={onKonfirmasi}>Ya, Hapus</button>
        </div>
      </div>
    </div>
  );
}
